mapper.select:
select C.COMPANY_NO ,C.BUSINESS_NO ,C.COMPANY_NAME ,C.REPRESENTATIVE_NAME ,C.PHONE ,C.EMAIL ,C.CREATED_ON ,C.STATUS ,CS_MEMO.MEMO ,S.FIELD from( select * from( select ROWNUM RN, A.* from( select COM.COMPANY_NO ,COM.BUSINESS_NO ,COM.COMPANY_NAME ,COM.REPRESENTATIVE_NAME ,COM.PHONE ,COM.EMAIL ,COM.CREATED_ON ,COM.STATUS from COMPANY COM
and COM.BUSINESS_NO like '%' || #{businessNo} || '%'
and COM.COMPANY_NAME like '%' || #{companyName} || '%'
and COM.REPRESENTATIVE_NAME like '%' || #{representativeName} || '%'
and COM.STATUS = #{status}
and exists ( select 1 from COMPANY_SPECIALTY CS2 inner join SPECIALTY S2 on S2.SPECIALTY_NO = CS2.SPECIALTY_NO where CS2.COMPANY_NO = COM.COMPANY_NO and S2.FIELD = #{option}
and CS2.MEMO like '%' || #{etcMemo} || '%'
)
order by COM.COMPANY_NO desc ) A where ROWNUM <= #{endRow} ) B where B.RN >= #{startRow} ) C left join COMPANY_SPECIALTY CS on(CS.COMPANY_NO = C.COMPANY_NO) left join SPECIALTY S on(S.SPECIALTY_NO = CS.SPECIALTY_NO) left join COMPANY_SPECIALTY CS_MEMO on (CS_MEMO.COMPANY_NO = C.COMPANY_NO and CS_MEMO.SPECIALTY_NO = ( select SPECIALTY_NO from SPECIALTY where FIELD = '기타' ))

select count(*) from COMPANY COM
and COM.BUSINESS_NO like '%' || #{businessNo} || '%'
and COM.COMPANY_NAME like '%' || #{companyName} || '%'
and COM.REPRESENTATIVE_NAME like '%' || #{representativeName} || '%'
and COM.STATUS = #{status}
and exists ( select 1 from COMPANY_SPECIALTY CS2 inner join SPECIALTY S2 on S2.SPECIALTY_NO = CS2.SPECIALTY_NO where CS2.COMPANY_NO = COM.COMPANY_NO and S2.FIELD = #{option}
and CS2.MEMO like '%' || #{etcMemo} || '%'
)

mapper.update:
update COMPANY
set
  BUSINESS_NO = #{businessNo}
  ,COMPANY_NAME = #{companyName}
  ,REPRESENTATIVE_NAME = #{representativeName}
  ,PHONE = #{phone}
  ,EMAIL = #{email}
  ,CREATED_ON = #{createdOn}
  ,STATUS = #{status}
